PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE expenses_outbox (
    id            TEXT PRIMARY KEY,         -- UUID v4 от Mini App
    user_id       TEXT NOT NULL,            -- Telegram user ID
    date          TEXT NOT NULL,
    account_id    TEXT,                     -- из bootstrap (может быть NULL пока)
    amount        REAL NOT NULL,
    currency      TEXT NOT NULL,
    category_id   TEXT,
    note          TEXT,
    created_at    TEXT NOT NULL,            -- момент ввода в Mini App
    confirmed_at  TEXT                      -- MacBook подтвердил приём
);
CREATE TABLE authorized_users (
    telegram_id   TEXT PRIMARY KEY,
    name          TEXT,
    created_at    TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE accounts (
    id          TEXT PRIMARY KEY,
    name        TEXT NOT NULL,
    type        TEXT NOT NULL,
    currency    TEXT NOT NULL,
    is_active   INTEGER NOT NULL DEFAULT 1,
    color       TEXT,
    updated_at  TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE categories (
    id          TEXT PRIMARY KEY,
    name        TEXT NOT NULL,
    type        TEXT NOT NULL,
    parent_id   TEXT,
    emoji       TEXT,
    color       TEXT,
    sort_order  INTEGER NOT NULL DEFAULT 0,
    is_active   INTEGER NOT NULL DEFAULT 1,
    updated_at  TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE currencies (
    code        TEXT PRIMARY KEY,
    name        TEXT NOT NULL,
    emoji       TEXT,
    is_crypto   INTEGER NOT NULL DEFAULT 0,
    decimals    INTEGER NOT NULL DEFAULT 2
);
CREATE TABLE rate_limit (
    user_id      TEXT NOT NULL,
    window_start TEXT NOT NULL,
    count        INTEGER NOT NULL DEFAULT 0,
    PRIMARY KEY (user_id, window_start)
);
CREATE TABLE device_heartbeats (
    device_id              TEXT PRIMARY KEY,        -- 'macbook' (один пока)
    last_seen              TEXT NOT NULL,           -- любой touch к Worker
    last_sync_attempt_at   TEXT,                    -- момент последнего sync (успех или ошибка)
    last_sync_success_at   TEXT,                    -- момент последнего успешного sync
    last_pulled            INTEGER NOT NULL DEFAULT 0,
    last_inserted          INTEGER NOT NULL DEFAULT 0,
    last_confirmed         INTEGER NOT NULL DEFAULT 0,
    last_error             TEXT,
    notes                  TEXT
);
CREATE TABLE expenses_cache (
    id           TEXT PRIMARY KEY,
    date         TEXT NOT NULL,
    account_id   TEXT,
    amount       REAL NOT NULL,
    currency     TEXT NOT NULL,
    category_id  TEXT,
    note         TEXT,
    source       TEXT NOT NULL,
    created_at   TEXT NOT NULL,
    cached_at    TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE expenses (
    id               TEXT PRIMARY KEY,        -- UUID v4
    date             TEXT NOT NULL,           -- YYYY-MM-DD
    account_id       TEXT,                    -- nullable, references accounts(id)
    amount           REAL NOT NULL,
    currency         TEXT NOT NULL,
    category_id      TEXT,                    -- nullable, references categories(id)
    note             TEXT,
    source           TEXT NOT NULL,           -- 'mini_app','csv_ok_import','manual','migration'
    source_record_id TEXT,
    user_id          TEXT NOT NULL,           -- telegram id, owner of the record
    created_at       TEXT NOT NULL,           -- момент создания на клиенте
    updated_at       TEXT NOT NULL DEFAULT (datetime('now')),
    deleted_at       TEXT                     -- soft delete
);
CREATE INDEX idx_outbox_created ON expenses_outbox(created_at);
CREATE INDEX idx_outbox_confirmed ON expenses_outbox(confirmed_at);
CREATE INDEX idx_outbox_user ON expenses_outbox(user_id);
CREATE INDEX idx_cache_date ON expenses_cache(date DESC, created_at DESC);
CREATE INDEX idx_expenses_date ON expenses(date DESC);
CREATE INDEX idx_expenses_user_date ON expenses(user_id, date DESC);
CREATE INDEX idx_expenses_updated ON expenses(updated_at DESC);
CREATE INDEX idx_expenses_deleted ON expenses(deleted_at);
